sql:
SELECT SUM(translated_words) AS total_translated_words
FROM translation_statistics
WHERE project_id = 0 AND language_id = 0;

SELECT project_name
FROM translation_projects
WHERE status = 'in progress';

SELECT project_name
FROM translation_projects
ORDER BY project_name;

SELECT original_content, translated_content
FROM translations
WHERE translation_id = 1;

SELECT COUNT(*) AS total_pending_translations
FROM translations
WHERE language_id = 1 AND status = 'pending review';

SELECT up_to_date, total_words
FROM translation_status
WHERE language_id = 1 AND project_id = 0;

SELECT AVG(ts.up_to_date) AS average_up_to_date_percentage
FROM translation_status ts
WHERE ts.project_id = 1;

SELECT 
  (SELECT COUNT(*) FROM translation_projects WHERE status = 'in progress') AS in_progress_count, 
  (SELECT COUNT(*) FROM translation_projects) AS total_projects;

SELECT MIN(translated_words) AS min_translated_words
FROM translation_statistics
WHERE project_id = 0;

SELECT project_name
FROM translation_projects
WHERE project_id = 1;

external_knowledge:
A large project is defined as having more than 1000 total words; substantial translation progress refers to an average number of translated words greater than 500; 
Translation projects are considered completed if the 'status' column is 'completed' in the 'translation_projects' table; 
Approved translation reviews are indicated by 'is_approved' equal to 1 in the 'reviews' table.

